#!/usr/bin/env bash
# setup-rootless-docker.sh — post-rebase one-time setup of the per-user
# rootless Docker daemon for the current user. Idempotent: safe to re-run.
#
# Why this exists:
#   The image ships with docker-ce + docker-ce-rootless-extras and masks
#   the rootful system docker.service. What it CANNOT do at build time is
#   generate the per-user docker.service unit (it lives in
#   ~/.config/systemd/user/, generated by dockerd-rootless-setuptool.sh
#   from the user template) or write the user's subuid/subgid mapping.
#   Both are per-user and have to be done as the user, after rebase.
#
# Flow:
#   1. Refuse to run as root.
#   2. Enable lingering for the user (so the per-user daemon survives
#      logout; rootless needs this).
#   3. Detect missing subuid/subgid. If missing, hand off to
#      dockerd-rootless-setuptool.sh install INTERACTIVELY (the tool
#      needs sudo to write /etc/subuid, and silently dropping that
#      prompt is exactly the bug this script exists to prevent).
#   4. If the per-user docker.service unit is missing, run the setup
#      tool again (it's idempotent: it won't redo work that's done).
#   5. Enable + start the per-user unit.
#   6. Warn if DOCKER_HOST is set to a rootful path (it would silently
#      override the context after this script runs).
#   7. Call verify-rootless-docker.sh to confirm the final state.

set -euo pipefail

# Color helpers, but only when stdout is a tty. Logs into build logs would
# otherwise be polluted with escape codes.
if [[ -t 1 ]]; then
    C_OK=$'\033[1;32m'; C_WARN=$'\033[1;33m'; C_ERR=$'\033[1;31m'; C_RST=$'\033[0m'
else
    C_OK=''; C_WARN=''; C_ERR=''; C_RST=''
fi
log()  { printf '%s[setup-rootless]%s %s\n' "$C_OK"   "$C_RST" "$*"; }
warn() { printf '%s[setup-rootless]%s %s\n' "$C_WARN" "$C_RST" "$*" >&2; }
err()  { printf '%s[setup-rootless]%s %s\n' "$C_ERR"  "$C_RST" "$*" >&2; }

require() {
    command -v "$1" >/dev/null 2>&1 || { err "missing required tool: $1"; exit 1; }
}

# --- 1. Refuse to run as root ---------------------------------------------
if [[ "$EUID" -eq 0 ]]; then
    err "this script must run as your user, not as root."
    err "it writes files under \$HOME and uses dockerd-rootless-setuptool.sh"
    err "to add subuid/subgid entries for \$USER. running as root means it"
    err "would configure the root user, not you."
    exit 2
fi

require docker
require systemctl
require dockerd-rootless-setuptool.sh

USER_NAME="${USER}"
HOME_DIR="${HOME}"
USER_UID="$(id -u)"

log "user          : ${USER_NAME} (uid=${USER_UID})"
log "home          : ${HOME_DIR}"

# --- 2. Enable lingering so the per-user daemon survives logout ----------
# loginctl is per-host; needs sudo. No-op if already enabled.
if ! loginctl show-user "${USER_NAME}" 2>/dev/null | grep -q '^Linger=yes'; then
    log "enabling lingering for ${USER_NAME} (requires sudo)"
    if ! sudo -n loginctl enable-linger "${USER_NAME}" 2>/dev/null; then
        err "could not enable linger non-interactively; run manually:"
        err "    sudo loginctl enable-linger ${USER_NAME}"
        exit 1
    fi
else
    log "linger already enabled for ${USER_NAME}"
fi

# --- 3. Detect subuid/subgid and hand off to the setup tool --------------
# The setup tool will prompt for sudo to write subuid/subgid. We must
# NOT pre-write them here from a non-root context; they're owned by root
# and silently dropping the prompt was the original bug.
subuid_has_entry() {
    grep -qE "^${USER_NAME}:" /etc/subuid 2>/dev/null
}
subgid_has_entry() {
    grep -qE "^${USER_NAME}:" /etc/subgid 2>/dev/null
}

if subuid_has_entry && subgid_has_entry; then
    log "subuid/subgid already have an entry for ${USER_NAME}"
else
    warn "no subuid/subgid entry for ${USER_NAME} yet."
    warn "the setup tool will ask for your sudo password to add it."
    warn "this is expected; it only happens once per fresh install."
    warn
    # Exec replaces this script's process; the tool inherits the tty so
    # the sudo prompt works. If the user types the wrong password, the
    # tool exits non-zero and the parent shell returns to the prompt.
    exec dockerd-rootless-setuptool.sh install
fi

# --- 4. Per-user docker.service unit --------------------------------------
USER_UNIT="${HOME_DIR}/.config/systemd/user/docker.service"
if [[ ! -f "${USER_UNIT}" ]]; then
    log "per-user docker.service unit not found; running setup tool"
    # The setup tool is idempotent. If subuid/subgid are already set
    # (which we just confirmed), this is a no-op for them and only
    # generates the unit + enables it.
    dockerd-rootless-setuptool.sh install
else
    log "per-user unit already present: ${USER_UNIT}"
fi

# --- 5. Enable + start the per-user unit ---------------------------------
# Use `systemctl --user` so the unit lives in the user systemd instance.
# `--now` enables and starts in one shot; re-running on an already-active
# unit is a no-op.
log "enabling and starting docker.service in the user systemd instance"
systemctl --user enable --now docker.service

# `systemctl --user` requires the user systemd instance to be running.
# In a fresh graphical login it is; in a headless context (ssh without
# linger, etc.) it might not be. Check now so we don't lie about success.
if ! systemctl --user is-active docker.service >/dev/null 2>&1; then
    err "docker.service did not come up active."
    err "check: systemctl --user status docker.service"
    err "common cause: the user systemd instance isn't running."
    err "fix:     loginctl enable-linger ${USER_NAME} (already done above),"
    err "         then log out and log back in once to start the instance."
    exit 1
fi

# --- 6. Warn if DOCKER_HOST is pinned to a rootful path -------------------
# This is the silent-overriding-context bug. A user's .bashrc or
# .config/environment.d/ can set DOCKER_HOST=unix:///var/run/docker.sock,
# and that overrides whatever `docker context use rootless` set.
# We only WARN, not fix, because the right fix depends on the user's
# shell init conventions and we don't want to clobber their config.
if [[ -n "${DOCKER_HOST:-}" ]]; then
    warn "DOCKER_HOST is set in your environment: ${DOCKER_HOST}"
    warn "this will override the docker context. unset it or change it to"
    warn "${XDG_RUNTIME_DIR:-/run/user/${USER_UID}}/docker.sock in your"
    warn "shell init (.bashrc, .zshrc, /etc/environment.d/, etc.)"
fi

# --- 7. Verify -----------------------------------------------------------
VERIFY_BIN="/usr/local/bin/verify-rootless-docker.sh"
if [[ -x "${VERIFY_BIN}" ]]; then
    log "running verify-rootless-docker.sh"
    echo
    "${VERIFY_BIN}" || {
        rc=$?
        err "verification failed (exit ${rc})"
        err "do NOT ignore this; rootless is not actually working."
        exit "${rc}"
    }
    echo
    log "rootless Docker is ready. reminder:"
    log "  - the per-user daemon lives in your systemd user instance."
    log "  - if you ever log out without linger, it would stop; linger is on."
    log "  - re-run this script after any rpm-ostree upgrade that touches"
    log "    docker-ce or docker-ce-rootless-extras."
else
    warn "${VERIFY_BIN} not found; skipping final verification."
    warn "this is unexpected: the script should ship in the same image."
fi
